steps.input:
{"command": "node - <<'NODE'
const rows = {
  A: {strength:480, density:2.7, cost:14},
  B: {strength:870, density:4.4, cost:24},
  C: {strength:692, density:1.8, cost:38},
};
const strengths = Object.values(rows).map(r=>r.strength);
const densities = Object.values(rows).map(r=>r.density);
const costs = Object.values(rows).map(r=>r.cost);
const min = arr => Math.min(...arr), max = arr => Math.max(...arr);
const smin=min(strengths), smax=max(strengths), dmin=min(densities), dmax=max(densities), cmin=min(costs), cmax=max(costs);
for (const [k,r] of Object.entries(rows)) {
  const s = (r.strength-smin)/(smax-smin);
  const m = (dmax-r.density)/(dmax-dmin);
  const c = (cmax-r.cost)/(cmax-cmin);
  const manuf = 0.7*m + 0.3*c;
  const total = 0.4*s + 0.3*m + 0.2*c + 0.1*manuf;
  console.log(k, {s:+s.toFixed(6), m:+m.toFixed(6), c:+c.toFixed(6), manuf:+manuf.toFixed(6), total:+total.toFixed(6)});
}
console.log({smin,smax,dmin,dmax,cmin,cmax});
NODE"}

